import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { siteStrings } from '../config';
import { siteActions } from '../actions';
import { ContentControl } from '../ContentControl';
import { ArticleItem } from '../../../includes';
import { agroAdminRouteNames } from '../../routeNames';


const style = theme => ({
    root: {
    }
})
class _Blogs extends Component {
    componentDidMount() {
        const {
            [siteStrings.site] : site,
            dispatch,
        } = this.props;
        if(!site) siteActions.getSiteInfo()(dispatch);
    }
    
    render() {
        const {
            classes,
            [siteStrings.site] : site,
        } = this.props;
        const {item : home} = site && site.getFirstObjectByPropValue("name", "blogs") || {};
        return (
            <div className={classes.root}>
                {home && home.values && home.values.map((item, index)=>{
                    return <ArticleItem 
                        {...item} 
                        key={index} 
                        editable 
                        toUrl={{pathname : agroAdminRouteNames.blogView_+item._id, state : item}}
                        editLink={{pathname : agroAdminRouteNames.blogEdit_ + item._id, state : item}}/>
                })}
            </div>
        );
    }
}


_Blogs.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({siteReducer}) => ({
    [siteStrings.site] : siteReducer[siteStrings.site],
})


export const Blogs = connect(mapStateToProps)(withStyles(style)(_Blogs));
export {Blogs as default}